var correlationId = mc.getProperty('correlation.id');
if (correlationId == null || String(correlationId).trim().length === 0) {
    correlationId = 'mi-' + Date.now().toString(36) + '-' +
        Math.random().toString(36).substring(2, 12);
    mc.setProperty('correlation.id', correlationId);
}
